mapper.select:
SELECT v.stock_virtual_no, f.contract_no, f.our_company_name, f.company_name, f.business_type, f.products_name, f.dept_id, f.match_user_name, f.total_number, v.min_sell_price, t.buy_price, t.sell_price, f.credit_cycle, f.warehouse_amount, f.transport_amount, f.stevedorage, f.insurance_rate, f.contract_time, h1.warehouse_out_date as 'realWarehoseDate', h2.pay_date as 'payFullTime', h3.confirm_receipt_date as 'confirmDate', f.match_credit_flg, k.deal_price as "kubBuyPrice", h2.pay_amount as "sumPayAmount", h4.receive_date, h4.receive_amount as 'sumReceiveAmount', f.total_amount FROM t_ctr_contract b LEFT JOIN t_ctr_contract c ON b.virtual_contract_id = c.id LEFT JOIN t_ctr_contract_settlement t ON t.buy_contract_id = b.id left join t_ctr_contract d on d.contract_no = REPLACE(c.contract_no, 'KUX', 'KUB') LEFT JOIN t_ctr_contract f ON f.id = t.sell_contract_id LEFT JOIN ( SELECT contract_id, max( warehouse_out_date ) AS warehouse_out_date FROM t_apply_delivery_out WHERE STATUS = 'D' GROUP BY contract_id ) h1 ON h1.contract_id = f.id LEFT JOIN ( SELECT contract_id, max( pay_date ) AS pay_date,sum(IFNULL(pay_amount,0)) as pay_amount FROM t_apply_pay WHERE STATUS = 'D' GROUP BY contract_id ) h2 ON h2.contract_id = d.id LEFT JOIN ( SELECT contract_id, max( confirm_receipt_date ) AS confirm_receipt_date FROM t_apply_confirm_receipt WHERE STATUS = 'D' GROUP BY contract_id ) h3 ON h3.contract_id = f.id LEFT JOIN ( SELECT contract_id, max( receive_date ) AS receive_date,sum( receive_amount ) AS receive_amount FROM t_apply_receive WHERE STATUS = 'D' GROUP BY contract_id) h4 on h4.contract_id = f.id LEFT JOIN t_stock_virtual v ON v.link_contract_id = b.id LEFT JOIN t_stock_inventory k ON v.biz_apply_virtual_id = k.id
c.virtual_type = 'KC' AND b.`status` != 'C' AND b.contract_status != 'C' AND f.`status` != 'C' AND f.contract_status != 'C'
and v.stock_virtual_no like concat('%',#{stockVirtualNo},'%')
and f.contract_no like concat('%',#{sellContractNo},'%')
and t.dept_id =#{deptId}
and f.products_name like concat('%',#{productName},'%')
and f.business_Type=#{businessType} and f.match_credit_flg=#{matchCreditFlg}
and DATE_FORMAT(f.contract_time, '%Y-%m-%d') >=#{contractTimeBegin}
and DATE_FORMAT(f.contract_time, '%Y-%m-%d') <=#{contractTimeEnd}
and f.our_company_name in
#{ourCompanyList[${index}],jdbcType=VARCHAR}
order by v.stock_virtual_no desc,f.contract_no desc
